svg.script:
const frames=[...document.querySelectorAll('g[id^="f"]')];
let i=0;
let last=performance.now();
const frameMs=1000/60;
function tick(now){
  if(i >= frames.length - 1){
    return;
  }
  if(now-last>=frameMs){
    frames[i].classList.remove('on');
    i+=1;
    frames[i].classList.add('on');
    last=now;
  }
  requestAnimationFrame(tick);
}
requestAnimationFrame(tick);
